.btn {
  display: inline-flex;
  align-items: center;
  padding: 4px 10px;
  cursor: pointer;
  background: #3a3d41;
  border: none;
  color: inherit;
  border-radius: 4px;
  font-size: 12px;
  line-height: 1.4;
  white-space: nowrap;
